function initMultiStepForm(){var form=qs('#es-lead-form');if(!form)return;var currentStep=0;var panels=form.querySelectorAll('.es-form-panel');var indicators=form.querySelectorAll('.es-form-step-indicator');var stepLabel=qs('.es-form-step-label',form);function goToStep(n){panels.forEach(function(p){p.classList.remove('active');});indicators.forEach(function(ind,i){ind.classList.remove('active');if(i<n)ind.classList.add('done');else ind.classList.remove('done');if(i===n)ind.classList.add('active');});panels[n].classList.add('active');currentStep=n;var labels=['Step 1 of 3 — <strong>Your Facility</strong>','Step 2 of 3 — <strong>Your Info</strong>','Step 3 of 3 — <strong>Project Details</strong>'];if(stepLabel)stepLabel.innerHTML=labels[n];hsTrack.track('form_step',{step:n+1});}
form.querySelectorAll('.es-form-next').forEach(function(btn){btn.addEventListener('click',function(){if(currentStep<panels.length-1)goToStep(currentStep+1);});});form.querySelectorAll('.es-form-back').forEach(function(btn){btn.addEventListener('click',function(){if(currentStep>0)goToStep(currentStep-1);});});goToStep(0);form.addEventListener('submit',function(e){e.preventDefault();var data={};new FormData(form).forEach(function(v,k){data[k]=v;});data.visit_count=visitCount;data.ab_tests=JSON.stringify(abTests);data.session_events=sessionStorage.getItem('es_events')||'[]';fetch('https://webhooks.tasklet.ai/v1/public/webhook?token=26210d713c946da132f60d6d54863045',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)}).catch(function(){});hsTrack.track('form_submitted',{facility_type:data.type,sqft:data.sqft});form.innerHTML='<div style="text-align:center;padding:40px 0">'+'<div style="font-family:Space Grotesk,sans-serif;font-size:24px;font-weight:700;margin-bottom:12px">Thank you.</div>'+'<div style="color:'+GRAY+';font-size:14px">Our team will review your facility details and reach out within 48 hours to schedule your free lighting audit.</div>'+'</div>';});}
function initEnergyCounter(){var el=qs('.es-energy-counter-num');if(!el)return;var base=14237891;var startOfYear=new Date(2026,0,1).getTime();var growthPerMs=0.5/1000;function update(){var elapsed=Date.now()-startOfYear;var current=base+Math.floor(elapsed*growthPerMs);el.textContent=current.toLocaleString()+' kWh';requestAnimationFrame(update);}
update();}
function initUrgencyTimer(){var timerEl=qs('.es-urgency-timer');if(!timerEl)return;var now=new Date();var qMonth=Math.ceil((now.getMonth()+1)/3)*3;var deadline=new Date(now.getFullYear(),qMonth,0,23,59,59);if(deadline-now<0)deadline=new Date(now.getFullYear(),qMonth+3,0,23,59,59);function update(){var diff=deadline-new Date();if(diff<=0)return;var days=Math.floor(diff/86400000);var hours=Math.floor((diff%86400000)/3600000);var mins=Math.floor((diff%3600000)/60000);var secs=Math.floor((diff%60000)/1000);var digits=timerEl.querySelectorAll('.es-urgency-digit');if(digits.length>=4){digits[0].firstChild.textContent=days;digits[1].firstChild.textContent=hours;digits[2].firstChild.textContent=mins;digits[3].firstChild.textContent=secs;}
requestAnimationFrame(update);}
update();}
