function buildClientPortalPage(contentWrap){var hero=$('div',{class:'es-cp-hero'});hero.innerHTML='<a href="#" class="es-back-link" style="text-align:left" onclick="navigateTo(\'home\');return false;">Back to Home</a>'+'<div class="es-subpage-eyebrow rv">Client Portal</div>'+'<div class="es-subpage-title rv rv-d1">Track Your<br>Energy Savings</div>'+'<div class="es-subpage-sub rv rv-d2">Access real-time performance data, ROI dashboards, and project milestones for your Energie Solutions installation.</div>';contentWrap.appendChild(hero);var login=$('div',{class:'es-cp-login'});login.innerHTML='<div class="es-cp-login-box rv">'+'<div class="es-cp-login-title">Sign In to Your Dashboard</div>'+'<form id="es-cp-form">'+'<div class="es-form-group"><label>Project ID</label><input type="text" name="project_id" placeholder="e.g. ES-2026-0142" required/></div>'+'<div class="es-form-group"><label>Email Address</label><input type="email" name="email" placeholder="your@company.com" required/></div>'+'<div class="es-form-nav"><button type="submit" class="es-form-submit" style="width:100%">Access Dashboard</button></div>'+'</form>'+'</div>';contentWrap.appendChild(login);setTimeout(function(){var form=qs('#es-cp-form');if(form){form.addEventListener('submit',function(e){e.preventDefault();var data={};new FormData(form).forEach(function(v,k){data[k]=v;});data.type='client_portal_login';fetch('https://webhooks.tasklet.ai/v1/public/webhook?token=26210d713c946da132f60d6d54863045',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)}).catch(function(){});form.innerHTML='<div style="text-align:center;padding:24px 0"><div style="font-family:Space Grotesk,sans-serif;font-size:20px;font-weight:700;margin-bottom:8px">Request Received</div><div style="color:rgba(255,255,255,0.5);font-size:14px">Our team will verify your project and send dashboard access credentials within 24 hours.</div></div>';});}},100);var features=$('div',{class:'es-cp-features'});var featureItems=[{icon:'chart',title:'Real-Time Performance Tracking',desc:'Monitor your infrastructure performance and operating cost reductions, with live kWh and dollar comparisons to baseline.'},{icon:'dollar',title:'ROI Dashboard',desc:'Track cumulative savings vs. project investment with projected payback timeline and break-even indicators.'},{icon:'clock',title:'Project Timeline',desc:'View installation milestones, commissioning dates, and ongoing maintenance schedule at a glance.'},{icon:'shield',title:'Maintenance Schedules',desc:'Automated maintenance reminders and warranty tracking for all installed fixtures and controls.'},{icon:'leaf',title:'CO2 Reduction Metrics',desc:'Quantify your environmental impact with carbon reduction tracking and sustainability reporting.'},{icon:'zap',title:'Optimization Opportunities',desc:'Recommendations for additional value creation through controls upgrades, HVAC governance, and utility rate optimization.'}];var featHTML='<div class="es-cp-features-title rv">What You\'ll Find Inside</div><div class="es-cp-features-grid">';featureItems.forEach(function(f,i){featHTML+='<div class="es-cp-feature rv rv-d'+(i%4+1)+'"><div class="es-cp-feature-icon">'+ICONS[f.icon]+'</div><div class="es-cp-feature-title">'+f.title+'</div><div class="es-cp-feature-desc">'+f.desc+'</div></div>';});featHTML+='</div>';features.innerHTML=featHTML;contentWrap.appendChild(features);}
